create or replace function public.submit_training_answer(p_session_id uuid,p_session_exercise_id uuid,p_answer jsonb,p_client_attempt_id uuid,p_response_time_ms integer default null,p_hints_used integer default 0) returns jsonb language plpgsql security definer set search_path=public as $$ declare v_user uuid:=auth.uid(); v_type text; v_rules jsonb; v_attempt int; v_correct boolean:=false; v_score numeric:=0; v_answer_id uuid; v_exercise uuid; begin if v_user is null then raise exception 'unauthenticated'; end if; if exists(select 1 from training_answers where user_id=v_user and client_attempt_id=p_client_attempt_id) then return (select evaluation_details||jsonb_build_object('answerId',id,'idempotent',true) from training_answers where user_id=v_user and client_attempt_id=p_client_attempt_id); end if; select e.id,e.type,r.evaluation_config into v_exercise,v_type,v_rules from training_session_exercises se join training_sessions s on s.id=se.session_id join training_exercises e on e.id=se.exercise_id join training_exercise_evaluation_rules r on r.exercise_id=e.id where se.id=p_session_exercise_id and se.session_id=p_session_id and s.user_id=v_user and s.status in('not_started','in_progress'); if v_exercise is null then raise exception 'session_exercise_forbidden'; end if; select coalesce(max(attempt_number),0)+1 into v_attempt from training_answers where session_exercise_id=p_session_exercise_id and user_id=v_user; v_correct:=case v_type when 'single_choice' then p_answer->>'optionId'=v_rules->>'correctOptionId' when 'scenario' then p_answer->>'optionId'=v_rules->>'correctOptionId' when 'true_false' then (p_answer->>'value')::boolean=(v_rules->>'correctValue')::boolean when 'multiple_choice' then (select array_agg(x order by x) from jsonb_array_elements_text(p_answer->'optionIds') x)=(select array_agg(x order by x) from jsonb_array_elements_text(v_rules->'correctOptionIds') x) when 'ordering' then p_answer->'itemIds'=v_rules->'correctOrder' when 'flashcard' then p_answer->>'rating'='knew' else false end; v_score:=case when v_type='flashcard' then case p_answer->>'rating' when 'knew' then 100 when 'almost' then 60 else 20 end when not v_correct then 0 when v_attempt>1 then 70 when p_hints_used>0 then 80 else 100 end; insert into training_answers(client_attempt_id,user_id,session_id,session_exercise_id,answer,attempt_number,is_correct,score,hints_used,response_time_ms,evaluation_details) values(p_client_attempt_id,v_user,p_session_id,p_session_exercise_id,p_answer,v_attempt,v_correct,v_score,p_hints_used,p_response_time_ms,jsonb_build_object('isCorrect',v_correct,'score',v_score,'retryAllowed',v_attempt<2,'feedback',case when v_correct then 'Buena decisión' else 'Revisa el principio y vuelve a intentarlo' end)) returning id into v_answer_id; update training_sessions set status='in_progress',started_at=coalesce(started_at,now()),updated_at=now() where id=p_session_id; return jsonb_build_object('answerId',v_answer_id,'isCorrect',v_correct,'score',v_score,'retryAllowed',v_attempt<2,'feedback',case when v_correct then 'Buena decisión' else 'Esta opción puede fortalecerse' end,'explanation',(select explanation from training_exercises where id=v_exercise),'idempotent',false); end $$;
grant execute on function public.submit_training_answer(uuid,uuid,jsonb,uuid,integer,integer) to authenticated;

create or replace function public.complete_training_session(p_session_id uuid) returns jsonb language plpgsql security definer set search_path=public as $$ declare v_user uuid:=auth.uid(); v_summary jsonb; v_today date:=current_date; begin if v_user is null then raise exception 'unauthenticated'; end if; if exists(select 1 from training_sessions where id=p_session_id and user_id=v_user and status='completed') then return (select result_summary from training_sessions where id=p_session_id); end if; if not exists(select 1 from training_sessions where id=p_session_id and user_id=v_user) then raise exception 'session_forbidden'; end if; select jsonb_build_object('correctAnswers',count(*) filter(where is_correct),'incorrectAnswers',count(*) filter(where not is_correct),'score',coalesce(round(avg(score)),0),'completedAt',now()) into v_summary from (select distinct on(session_exercise_id) * from training_answers where session_id=p_session_id and user_id=v_user order by session_exercise_id,attempt_number desc) a; update training_sessions set status='completed',completed_at=now(),updated_at=now(),result_summary=v_summary where id=p_session_id and user_id=v_user and status<>'completed'; insert into user_training_streaks(user_id,current_streak,longest_streak,last_training_date,weekly_activity) values(v_user,1,1,v_today,jsonb_build_object(v_today::text,true)) on conflict(user_id) do update set current_streak=case when user_training_streaks.last_training_date=v_today then user_training_streaks.current_streak when user_training_streaks.last_training_date=v_today-1 then user_training_streaks.current_streak+1 else 1 end,longest_streak=greatest(user_training_streaks.longest_streak,case when user_training_streaks.last_training_date=v_today-1 then user_training_streaks.current_streak+1 else 1 end),last_training_date=v_today,weekly_activity=user_training_streaks.weekly_activity||jsonb_build_object(v_today::text,true),updated_at=now(); return v_summary; end $$;
grant execute on function public.complete_training_session(uuid) to authenticated;

insert into training_categories(slug,name,sort_order) values('marketing','Marketing',1),('desarrollo-personal','Desarrollo personal',2),('liderazgo','Liderazgo',3),('finanzas','Finanzas',4),('emprendimiento','Emprendimiento',5) on conflict(slug) do update set name=excluded.name;
insert into training_skills(category_id,slug,name) select c.id,v.slug,v.name from training_categories c join(values('marketing','propuesta-de-valor','Propuesta de valor'),('desarrollo-personal','habitos','Hábitos'),('liderazgo','comunicacion','Comunicación'),('finanzas','finanzas-personales','Finanzas personales'),('emprendimiento','validacion-de-ideas','Validación de ideas'))v(category,slug,name) on c.slug=v.category on conflict(slug) do update set name=excluded.name;
insert into training_concepts(skill_id,slug,name,difficulty) select s.id,v.slug,v.name,'intermediate' from training_skills s join(values('propuesta-de-valor','cliente-especifico','Cliente específico'),('propuesta-de-valor','beneficio-claro','Beneficio claro'),('propuesta-de-valor','diferenciacion','Diferenciación'))v(skill,slug,name) on s.slug=v.skill on conflict(slug) do update set name=excluded.name;
insert into training_templates(slug,title,description,category_id,difficulty,estimated_minutes) select 'propuestas-de-valor','Propuestas de valor que realmente conectan','Construye propuestas claras, relevantes y diferenciadas.',id,'intermediate',7 from training_categories where slug='marketing' on conflict(slug) do update set title=excluded.title;

do $$ declare v_skill uuid; v_concept uuid; v_template uuid; v_exercise uuid; i int; v_types text[]:=array['single_choice','multiple_choice','true_false','ordering','flashcard','scenario','single_choice','scenario']; begin select id into v_skill from training_skills where slug='propuesta-de-valor'; select id into v_concept from training_concepts where slug='beneficio-claro'; select id into v_template from training_templates where slug='propuestas-de-valor'; for i in 1..8 loop insert into training_exercises(skill_id,concept_id,type,prompt,instruction,difficulty,hint,explanation,content,status) values(v_skill,v_concept,v_types[i],'Ejercicio '||i||': aplica una propuesta de valor clara.','Selecciona o construye la mejor respuesta.','intermediate','Busca cliente, resultado y diferencia.','Una propuesta útil comunica una transformación comprensible.',case v_types[i] when 'multiple_choice' then '{"options":[{"id":"client","label":"Cliente específico"},{"id":"result","label":"Resultado claro"},{"id":"generic","label":"Mensaje genérico"}]}'::jsonb when 'true_false' then '{}'::jsonb when 'ordering' then '{"items":[{"id":"client","label":"Cliente"},{"id":"problem","label":"Problema"},{"id":"result","label":"Resultado"}]}'::jsonb when 'flashcard' then '{"front":"¿Qué comunica una propuesta de valor?","back":"Cliente, problema, resultado y diferencia."}'::jsonb else '{"options":[{"id":"a","label":"Mensaje genérico"},{"id":"b","label":"Resultado específico para un cliente concreto"}]}'::jsonb end,'published') returning id into v_exercise; insert into training_exercise_evaluation_rules(exercise_id,evaluation_config) values(v_exercise,case v_types[i] when 'multiple_choice' then '{"correctOptionIds":["client","result"]}'::jsonb when 'true_false' then '{"correctValue":false}'::jsonb when 'ordering' then '{"correctOrder":["client","problem","result"]}'::jsonb else '{"correctOptionId":"b"}'::jsonb end); insert into training_template_exercises(template_id,exercise_id,position,is_final_challenge) values(v_template,v_exercise,i,i=8); end loop; end $$;
